import "./styles/Login.css";
import { useNavigate } from "react-router-dom";
import { useState } from "react";
import api from "../api/axios";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Student");
  const [genre, setGenre] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false); // ✅ added

  const handleLogin = async () => {
    if (loading) return; // ✅ prevent multiple clicks
    setLoading(true);

    try {
      setError("");

      const data = {
        email: email.trim(),
        password: password.trim(),
        role,
      };

      console.log("SENDING LOGIN:", data);

      if (role === "Librarian") {
        data.genre = genre.trim();
      }

      const res = await api.post("/auth/login", data);

      console.log("LOGIN SUCCESS RESPONSE:", res.data);

      const { role: userRole, genre: userGenre } = res.data;

      if (userRole === "Student") {
        navigate("/student-dashboard");
      } 
      else if (userRole === "Librarian") {
        const finalGenre = userGenre || genre;
        localStorage.setItem("librarianGenre", finalGenre);

        navigate("/librarian-dashboard", {
          state: { genre: finalGenre },
        });
      } 
      else if (userRole === "Admin") {
        navigate("/admin-dashboard");
      }

    } catch (err) {
      console.log("LOGIN ERROR RESPONSE:", err.response);
      setError(err.response?.data?.message || "Login failed");
    } finally {
      setLoading(false); // ✅ release lock
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <h2>Login</h2>

        {error && <p className="error">{error}</p>}

        <input
          type="email"
          placeholder="University Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <select value={role} onChange={(e) => setRole(e.target.value)}>
          <option>Student</option>
          <option>Librarian</option>
          <option>Admin</option>
        </select>

        {role === "Librarian" && (
          <input
            type="text"
            placeholder="Genre (Fantasy, Fiction...)"
            value={genre}
            onChange={(e) => setGenre(e.target.value)}
          />
        )}

        <button
          className="login-btn"
          onClick={handleLogin}
          disabled={loading}
        >
          {loading ? "Logging in..." : "Login"}
        </button>
      </div>
    </div>
  );
}

export default Login;
